"""
This module contains the Board class to represent the 8x8 checkers board.
"""

class Board:
    def __init__(self):
        self.board = [[None] * 8 for _ in range(8)]
        self.initialize_board()

    def initialize_board(self):
        # Initialize pieces on the board
        for row in range(3):
            for col in range((row + 1) % 2, 8, 2):
                self.board[row][col] = Piece("red")
        for row in range(5, 8):
            for col in range((row + 1) % 2, 8, 2):
                self.board[row][col] = Piece("black")

    def print_board(self):
        for row in self.board:
            print(" ".join(piece.char if piece else '.' for piece in row))
